import sys
import os
BASE_DIR = os.path.dirname(os.path.dirname(os.path.dirname(os.path.dirname(os.path.dirname(os.path.abspath(__file__))))))
sys.path.append(BASE_DIR)

from utils.profiling import profile_time_memory
from typing import List
import math


@profile_time_memory
def mysolution(nums: List[int]) -> List[int]:
    nums_length = len(nums)
    answer = [1] * nums_length
    # for idx in range(nums_length):
    #     prefix_list = nums[:idx]
    #     suffix_list = nums[idx+1:]
    #     for p in prefix_list:
    #         answer[idx] *= p
    #     for s in suffix_list:
    #         answer[idx] *= s
    for idx in range(nums_length):
        answer[idx] = math.prod(nums[:idx]) * math.prod(nums[idx+1:])

    return answer


@profile_time_memory
def othersolution(nums: List[int]) -> List[int]:
    n = len(nums)

    result = [0] * n

    left_product = 1
    for i in range(n):
        result[i] = left_product
        left_product *= nums[i]
    
    right_product = 1
    for i in range(n-1, -1, -1):
        result[i] *= right_product
        right_product *= nums[i]
    return result



